#include <bits/stdc++.h>using namespace std;typedef long long ll;int main() {    ll t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<ll> a(n,0);        for(int i=0;i<n;i++){            cin>>a[i];        }        set<int> st;        bool flag=false;        for(int i=0;i<n;i++){            a[i]+=(a[i]%10);            if(a[i]%10==0){                flag=true;            }            st.insert(a[i]);        }        if(flag){            if(st.size()==1){                cout<<"Yes"<<endl;            }            else{                cout<<"No"<<endl;            }        }        else{                set<int> st1;                for(int j=0;j<n;j++){                    a[j]%=20;                    while(a[j]+(a[j]%10)<20){                        a[j]+=a[j]%10;                    }                    st1.insert(a[j]);                }                if(st1.size()==1){                    cout<<"Yes"<<endl;                }                else{                    cout<<"No"<<endl;                }        }    }}